int arr[] = {1, 2, 3, 4, 5};
int n = 5;

int sum = 0;
for (int i = 0; i < n; i++) {
    sum += arr[i];
}
printf("sum: %d\n", sum);  // sum: 15

int j = 0;
while (j < n) {
    printf("%d ", arr[j]);
    j++;
}
// 1 2 3 4 5

